def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 11):
            weight = 1 / (j ** 1.5)
            term = (ratio ** j) * weight
            if j % 2 == 0:
                term *= 1.2
            else:
                term *= 0.8
            score += term
        remaining = capacity - item
        if remaining < 0.05 * capacity:
            score *= 2
        elif remaining < 0.2 * capacity:
            score *= 1.3
        else:
            score *= 0.9
        for k in range(n):
            if k != i:
                diff = abs(bins[k] - capacity)
                if diff < 0.1 * capacity:
                    score *= 1.1
                elif diff > 0.5 * capacity:
                    score *= 0.95
        if item > 0.8 * capacity:
            score += 0.5
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    for i in range(n):
        if priorities[i] == np.inf:
            priorities[i] = max_priority * 3
    return priorities
